            <button class="btn btn-sm btn-outline-secondary" @onclick="OnMoveRight" disabled="@IsMoving">Move Right →</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback OnMoveLeft { get; set; }
    [Parameter] public EventCallback OnMoveRight { get; set; }
    [Parameter] public bool IsMoving { get; set; }
}
"}

{"path": "/tmp/sv-db14e532a093478b9705ccc7478b20c7/Components/Board/AddTaskForm.razor", "file_text": "<div class="add-task-form">
    <div class="mb-2">
        <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="title" />
    </div>
    <div class="mb-2">
        <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="assignee" />
    </div>
    <div class="mb-2">
        <select class="form-select form-select-sm" @bind="priority">
            <option value="High">High</option>
            <option value="Medium">Medium</option>
            <option value="Low">Low</option>
        </select>
    </div>
    <div class="mb-2">
        <input type="date" class="form-control form-control-sm" @bind="dueDate" />
    </div>
    <div class="d-flex gap-2">
        <button class="btn btn-sm btn-primary" @onclick="HandleSave" disabled="@isSaving">Save</button>
        <button class="btn btn-sm btn-secondary" @onclick="OnCancel" disabled="@isSaving">Cancel</button>
    </div>
    @if (!string.IsNullOrEmpty(error))
    {
        <div class="text-danger mt-1 small">@error</div>
    }
</div>

@code {
    [Parameter, EditorRequired] public string Status { get; set; } = default!;
    [Parameter] public EventCallback<TaskItem> OnSave { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private string title = string.Empty;
    private string assignee = string.Empty;
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool isSaving;
    private string? error;

    [Inject] private ITaskService TaskService { get; set; } = default!;

    private async Task HandleSave()
    {
        if (string.IsNullOrWhiteSpace(title) || string.IsNullOrWhiteSpace(assignee))
        {
            error = "Title and assignee are required.";
            return;
        }

        error = null;
        isSaving = true;
        try
        {
            var created = await TaskService.CreateTaskAsync(title, assignee, priority, dueDate);
            await OnSave.InvokeAsync(created);
        }
        catch (Exception ex)
        {
            error = $"Failed to create task: {ex.Message}";
        }
        finally
        {
            isSaving = false;
        }
    }
}
"}

{"path": "/tmp/sv-db14e532a093478b9705ccc7478b20c7/Components/Board/KanbanColumn.razor", "file_text": "<div class="kanban-column">
    <div class="kanban-column-header">
        <h5>@ColumnName <span class="badge bg-secondary">@Tasks.Count</span></h5>
    </div>
    <div class="kanban-column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="HasLeft"
                      ShowMoveRight="HasRight"
                      IsMoving="movingTaskId == task.Id"
                      OnMoveLeft="() => HandleMove(task, MoveDirection.Left)"
                      OnMoveRight="() => HandleMove(task, MoveDirection.Right)" />
        }
    </div>
    <div class="kanban-column-footer">
        @if (showAddForm)
        {
            <AddTaskForm Status="@ColumnName"
                         OnSave="HandleTaskCreated"
                         OnCancel="() => showAddForm = false" />
        }
        else
        {
            <button class="btn btn-sm btn-outline-primary w-100" @onclick="() => showAddForm = true">+ Add Task</button>
        }
    </div>
</div>

@code {
    private enum MoveDirection { Left, Right }

    [Parameter, EditorRequired] public string ColumnName { get; set; } = default!;
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool HasLeft { get; set; }
    [Parameter] public bool HasRight { get; set; }
    [Parameter] public EventCallback<(int TaskId, string NewStatus)> OnTaskMoved { get; set; }
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }

    private bool showAddForm;
    private int? movingTaskId;

    private static readonly string[] ColumnOrder = { "To Do", "In Progress", "Done" };

    private async Task HandleMove(TaskItem task, MoveDirection direction)
    {
        var currentIndex = Array.IndexOf(ColumnOrder, ColumnName);
        var newIndex = direction == MoveDirection.Left ? currentIndex - 1 : currentIndex + 1;
        if (newIndex < 0 || newIndex >= ColumnOrder.Length) return;

        movingTaskId = task.Id;
        try
        {
            await OnTaskMoved.InvokeAsync((task.Id, ColumnOrder[newIndex]));
        }
        finally
        {
            movingTaskId = null;
        }
    }

    private async Task HandleTaskCreated(TaskItem newTask)
    {
        showAddForm = false;
        await OnTaskCreated.InvokeAsync(newTask);
    }
}
"}

{"path": "/tmp/sv-db14e532a093478b9705ccc7478b20c7/Components/Board/BoardSearchBar.razor", "file_text": "<div class="board-search-bar mb-3">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title..."
           value="@SearchText"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter] public string SearchText { get; set; } = string.Empty;
    [Parameter] public EventCallback<string> SearchTextChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? string.Empty;
        await SearchTextChanged.InvokeAsync(value);
    }
}
"}

