+<div class="kanban-column">
+    <div class="kanban-column-header">
+        <h5>@ColumnName <span class="badge bg-secondary">@Tasks.Count</span></h5>
+    </div>
+    <div class="kanban-column-body">
+        @foreach (var task in Tasks)
+        {
+            <TaskCard Task="task"
+                      ShowMoveLeft="HasLeft"
+                      ShowMoveRight="HasRight"
+                      IsMoving="movingTaskId == task.Id"
+                      OnMoveLeft="() => HandleMove(task, MoveDirection.Left)"
+                      OnMoveRight="() => HandleMove(task, MoveDirection.Right)" />
+        }
+    </div>
+    <div class="kanban-column-footer">
+        @if (showAddForm)
+        {
+            <AddTaskForm Status="@ColumnName"
+                         OnSave="HandleTaskCreated"
+                         OnCancel="() => showAddForm = false" />
