+    {
+        var currentIndex = Array.IndexOf(ColumnOrder, ColumnName);
+        var newIndex = direction == MoveDirection.Left ? currentIndex - 1 : currentIndex + 1;
+        if (newIndex < 0 || newIndex >= ColumnOrder.Length) return;
+
+        movingTaskId = task.Id;
+        try
