@page "/board"
@rendermode InteractiveServer
@using sv_db14e532a093478b9705ccc7478b20c7.Components.Board

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Project Board</h3>

@if (isLoading)
{
    <div class="d-flex justify-content-center p-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error loading tasks:</strong> @errorMessage
        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Tasks="allTasks" />
    <BoardSearchBar @bind-SearchText="searchText" />

    <div class="kanban-board d-flex gap-3">
        @foreach (var column in columns)
        {
            var columnTasks = FilteredTasks.Where(t => t.Status == column.Name).ToList();
            <KanbanColumn ColumnName="@column.Name"
                          Tasks="columnTasks"
                          HasLeft="column.Index > 0"
                          HasRight="column.Index < columns.Length - 1"
                          OnTaskMoved="HandleTaskMoved"
                          OnTaskCreated="HandleTaskCreated" />
        }
    </div>
}

@code {
    private record ColumnDef(string Name, int Index);

    private static readonly ColumnDef[] columns =
    {
        new("To Do", 0),
        new("In Progress", 1),
        new("Done", 2)
    };

    [Inject] private ITaskService TaskService { get; set; } = default!;

    private List<TaskItem> allTasks = new();
    private string searchText = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    private IEnumerable<TaskItem> FilteredTasks =>
        string.IsNullOrWhiteSpace(searchText)
            ? allTasks
            : allTasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleTaskMoved((int TaskId, string NewStatus) args)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(args.TaskId, args.NewStatus);
            var task = allTasks.FirstOrDefault(t => t.Id == args.TaskId);
            if (task is not null)
            {
                var index = allTasks.IndexOf(task);
                allTasks[index] = task with { Status = args.NewStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private Task HandleTaskCreated(TaskItem newTask)
    {
        allTasks.Add(newTask);
        return Task.CompletedTask;
    }
}

.kanban-board {
    overflow-x: auto;
}

.kanban-column {
    flex: 1;
    min-width: 280px;
    background-color: #f8f9fa;
    border-radius: 8px;
    display: flex;
    flex-direction: column;
}

.kanban-column-header {
    padding: 12px 16px;
    border-bottom: 1px solid #dee2e6;
}

.kanban-column-header h5 {
    margin: 0;
}

.kanban-column-body {
    padding: 12px;
    flex: 1;
    display: flex;
    flex-direction: column;
    gap: 10px;
    min-height: 200px;
}

.kanban-column-footer {
    padding: 12px;
    border-top: 1px solid #dee2e6;
}

/* Task card */
.task-card {
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    padding: 12px;
}

.task-card-header {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    margin-bottom: 8px;
}

.task-title {
    font-weight: 600;
    word-break: break-word;
}

.task-card-body {
    display: flex;
    justify-content: space-between;
    font-size: 0.85rem;
    color: #6c757d;
    margin-bottom: 8px;
}

.task-card-actions {
    display: flex;
    gap: 6px;
}

/* Priority badges */
.priority-badge {
    font-size: 0.7rem;
    padding: 2px 8px;
    border-radius: 12px;
    font-weight: 600;
    white-space: nowrap;
}

.priority-high {
    background-color: #dc3545;
    color: #fff;
}

.priority-medium {
    background-color: #ffc107;
    color: #212529;
}

.priority-low {
    background-color: #198754;
    color: #fff;
}

/* Add task form */
.add-task-form {
    background: #fff;
    border: 1px dashed #adb5bd;
    border-radius: 6px;
    padding: 12px;
}

/* Stats bar */
.stat-item {
    padding: 4px 12px;
    border-right: 1px solid #dee2e6;
}

.stat-item:last-child {
    border-right: none;
}

