+<h3 class="mb-3">Project Board</h3>
+
+@if (isLoading)
+{
+    <div class="d-flex justify-content-center p-5">
+        <div class="spinner-border" role="status">
+            <span class="visually-hidden">Loading...</span>
+        </div>
+    </div>
+}
+else if (errorMessage is not null)
+{
+    <div class="alert alert-danger" role="alert">
+        <strong>Error loading tasks:</strong> @errorMessage
+        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="LoadTasks">Retry</button>
+    </div>
+}
+else
+{
+    <BoardStatsBar Tasks="allTasks" />
+    <BoardSearchBar @bind-SearchText="searchText" />
+
+    <div class="kanban-board d-flex gap-3">
+        @foreach (var column in columns)
+        {
+            var columnTasks = FilteredTasks.Where(t => t.Status == column.Name).ToList();
+            <KanbanColumn ColumnName="@column.Name"
+                          Tasks="columnTasks"
+                          HasLeft="column.Index > 0"
+                          HasRight="column.Index < columns.Length - 1"
+                          OnTaskMoved="HandleTaskMoved"
+                          OnTaskCreated="HandleTaskCreated" />
+        }
+    </div>
+}
+
+@code {
+    private record ColumnDef(string Name, int Index);
+
+    private static readonly ColumnDef[] columns =
+    {
+        new("To Do", 0),
+        new("In Progress", 1),
+        new("Done", 2)
+    };
+
+    [Inject] private ITaskService TaskService { get; set; } = default!;
+
+    private List<TaskItem> allTasks = new();
+    private string searchText = string.Empty;
+    private bool isLoading = true;
+    private string? errorMessage;
+
+    private IEnumerable<TaskItem> FilteredTasks =>
+        string.IsNullOrWhiteSpace(searchText)
+            ? allTasks
+            : allTasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadTasks();
+    }
+
+    private async Task LoadTasks()
+    {
+        isLoading = true;
+        errorMessage = null;
+        try
+        {
+            allTasks = await TaskService.GetAllTasksAsync();
+        }
+        catch (Exception ex)
+        {
+            errorMessage = ex.Message;
+        }
+        finally
+        {
+            isLoading = false;
+        }
+    }
+
+    private async Task HandleTaskMoved((int TaskId, string NewStatus) args)
+    {
+        try
+        {
+            await TaskService.UpdateTaskStatusAsync(args.TaskId, args.NewStatus);
+            var task = allTasks.FirstOrDefault(t => t.Id == args.TaskId);
+            if (task is not null)
+            {
+                var index = allTasks.IndexOf(task);
+                allTasks[index] = task with { Status = args.NewStatus };
+            }
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to move task: {ex.Message}";
+        }
+    }
+
+    private Task HandleTaskCreated(TaskItem newTask)
+    {
+        allTasks.Add(newTask);
+        return Task.CompletedTask;
+    }
+}
+

