toolArgs.file_text:
.kanban-board {
    overflow-x: auto;
}

.kanban-column {
    flex: 1;
    min-width: 280px;
    background-color: #f8f9fa;
    border-radius: 8px;
    display: flex;
    flex-direction: column;
}

.kanban-column-header {
    padding: 12px 16px;
    border-bottom: 1px solid #dee2e6;
}

.kanban-column-header h5 {
    margin: 0;
}

.kanban-column-body {
    padding: 12px;
    flex: 1;
    display: flex;
    flex-direction: column;
    gap: 10px;
    min-height: 200px;
}

.kanban-column-footer {
    padding: 12px;
    border-top: 1px solid #dee2e6;
}

/* Task card */
.task-card {
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    padding: 12px;
}

.task-card-header {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    margin-bottom: 8px;
}

.task-title {
    font-weight: 600;
    word-break: break-word;
}

.task-card-body {
    display: flex;
    justify-content: space-between;
    font-size: 0.85rem;
    color: #6c757d;
    margin-bottom: 8px;
}

.task-card-actions {
    display: flex;
    gap: 6px;
}

/* Priority badges */
.priority-badge {
    font-size: 0.7rem;
    padding: 2px 8px;
    border-radius: 12px;
    font-weight: 600;
    white-space: nowrap;
}

.priority-high {
    background-color: #dc3545;
    color: #fff;
}

.priority-medium {
    background-color: #ffc107;
    color: #212529;
}

.priority-low {
    background-color: #198754;
    color: #fff;
}

/* Add task form */
.add-task-form {
    background: #fff;
    border: 1px dashed #adb5bd;
    border-radius: 6px;
    padding: 12px;
}

/* Stats bar */
.stat-item {
    padding: 4px 12px;
    border-right: 1px solid #dee2e6;
}

.stat-item:last-child {
    border-right: none;
}

